//
window.addEventListener("DOMContentLoaded", () => {

  // ── Post-process pass — applied to initial page and reusable for
  // newly loaded posts (infinite scroll). Operates on any root.
  const isFullPostView = !!document.querySelector('.post-body.full-content');

  function adjustPostTypography(root) {
      root.querySelectorAll('.post-outer').forEach(post => {
          const body = post.querySelector('.post-body');
          if (!body) return;

          const tagNodes = post.querySelectorAll('.post-tag, .hidden-tag');
          const tags = Array.from(tagNodes).map(t => {
              const raw = t.getAttribute('data-raw-tag') || t.textContent;
              return raw.trim().toLowerCase();
          });

          const isEnglish = tags.includes('english') || tags.includes('en');
          if (isEnglish) {
              // Style writes are batched via cssText to avoid multiple
              // style invalidations per post
              body.style.cssText += 'line-height:1.7;text-align:left;hyphens:auto;-webkit-hyphens:auto;word-spacing:0.05em;';
              body.setAttribute('lang', 'en');
          } else {
              body.style.cssText += 'line-height:2.2;text-align:justify;hyphens:none;-webkit-hyphens:none;word-spacing:normal;';
              body.setAttribute('lang', 'zh-Hans');
          }

          // Mirror the lang attribute onto the title so the CSS :lang()
          // rule can pick the right word-break behaviour for CJK vs Latin
          const title = post.querySelector('.post-title');
          if (title) title.setAttribute('lang', isEnglish ? 'en' : 'zh-Hans');

          // Add native lazy-loading + async decoding to article images
          // (Blogger doesn't emit these by default on user-uploaded images)
          body.querySelectorAll('img').forEach((img, idx) => {
              if (!img.hasAttribute('loading')) {
                  // First image on a single-post view is likely above the fold → eager
                  img.setAttribute('loading', idx === 0 && isFullPostView ? 'eager' : 'lazy');
              }
              if (!img.hasAttribute('decoding')) img.setAttribute('decoding', 'async');
          });
      });
  }

  adjustPostTypography(document);

  // Static translation dictionary — the sole source of tag translations.
  // No external translation API is called. Unknown tags fall through to
  // their original text (Chinese stays Chinese, English stays English).
  // To add a new tag, just append a pair here.
  const navDictionary = {
      // Navigation
      "Home": { zh: "首页", en: "Home" },
      "首页": { zh: "首页", en: "Home" },
      "首頁": { zh: "首页", en: "Home" },

      // Currently used labels on the blog
      "English": { zh: "英文", en: "English" },
      "中文": { zh: "中文", en: "Chinese" },
      "Novels": { zh: "小说", en: "Novels" },
      "小说": { zh: "小说", en: "Novels" },
      "Poems": { zh: "诗歌", en: "Poems" },
      "诗歌": { zh: "诗歌", en: "Poems" },
      "Prose": { zh: "散文", en: "Prose" },
      "散文": { zh: "散文", en: "Prose" },
      "第七层": { zh: "第七层", en: "7th Floor" },
      "7th Floor": { zh: "第七层", en: "7th Floor" },

      // Common categories — ready when you start using them
      "Life": { zh: "生活", en: "Life" },
      "生活": { zh: "生活", en: "Life" },
      "Tech": { zh: "科技", en: "Tech" },
      "科技": { zh: "科技", en: "Tech" },
      "技术": { zh: "技术", en: "Tech" },
      "Art": { zh: "艺术", en: "Art" },
      "艺术": { zh: "艺术", en: "Art" },

      // Writing & literature
      "Fiction": { zh: "小说", en: "Fiction" },
      "Poetry": { zh: "诗歌", en: "Poetry" },
      "Essay": { zh: "散文", en: "Essay" },
      "Essays": { zh: "散文", en: "Essays" },
      "随笔": { zh: "随笔", en: "Musings" },
      "笔记": { zh: "笔记", en: "Notes" },
      "Notes": { zh: "笔记", en: "Notes" },
      "日记": { zh: "日记", en: "Diary" },
      "Diary": { zh: "日记", en: "Diary" },
      "翻译": { zh: "翻译", en: "Translation" },
      "Translation": { zh: "翻译", en: "Translation" },
      "书评": { zh: "书评", en: "Book Reviews" },
      "读书": { zh: "读书", en: "Reading" },
      "Reading": { zh: "读书", en: "Reading" },
      "Reviews": { zh: "评论", en: "Reviews" },
      "评论": { zh: "评论", en: "Reviews" },

      // Hobbies & culture
      "摄影": { zh: "摄影", en: "Photography" },
      "Photography": { zh: "摄影", en: "Photography" },
      "旅行": { zh: "旅行", en: "Travel" },
      "Travel": { zh: "旅行", en: "Travel" },
      "美食": { zh: "美食", en: "Food" },
      "Food": { zh: "美食", en: "Food" },
      "音乐": { zh: "音乐", en: "Music" },
      "Music": { zh: "音乐", en: "Music" },
      "电影": { zh: "电影", en: "Films" },
      "Film": { zh: "电影", en: "Films" },
      "Movies": { zh: "电影", en: "Movies" },

      // Tech & thought
      "编程": { zh: "编程", en: "Programming" },
      "Programming": { zh: "编程", en: "Programming" },
      "Code": { zh: "代码", en: "Code" },
      "设计": { zh: "设计", en: "Design" },
      "Design": { zh: "设计", en: "Design" },
      "AI": { zh: "AI", en: "AI" },
      "教程": { zh: "教程", en: "Tutorials" },
      "Tutorial": { zh: "教程", en: "Tutorial" },
      "思考": { zh: "思考", en: "Thoughts" },
      "Thoughts": { zh: "思考", en: "Thoughts" },
      "随想": { zh: "随想", en: "Reflections" }
  };

  // Look up a tag in the dictionary. Unknown tags fall through to their
  // original text — Chinese tags keep Chinese in both modes, English
  // tags keep English in both modes. This is intentional: a broken
  // translation is worse than no translation.
  function getTranslations(rawTag) {
      return navDictionary[rawTag] || { zh: rawTag, en: rawTag };
  }

  // Apply translations to tags within `root`. Synchronous — no network,
  // no localStorage, resolves immediately. Safe to call repeatedly
  // (idempotent: writing the same translation twice is a no-op).
  function translateTagsIn(root) {
      root.querySelectorAll('.translatable-tag').forEach(link => {
          const rawTag = link.getAttribute('data-raw-tag');
          if (!rawTag) return;
          const trans = getTranslations(rawTag);
          const zhSpan = link.querySelector('.lang-zh');
          const enSpan = link.querySelector('.lang-en');
          if (zhSpan) zhSpan.textContent = trans.zh;
          if (enSpan) enSpan.textContent = trans.en;
      });
  }

  translateTagsIn(document);

  // Expose a combined post-processor for the infinite-scroll IIFE.
  // It wraps both passes (typography + tag translation) so newly
  // appended posts get the same treatment as the initial page.
  window.__rinuanPostProcess = function(root) {
      adjustPostTypography(root);
      translateTagsIn(root);
  };
});
