b:if.script:
//
// ====================================================================
// Comment module — encapsulated IIFE.
// Handles every aspect of the customized Blogger comment experience:
//   1. i18n strings for buttons (CN-simp / CN-trad / EN)
//   2. Form lifecycle: lazy iframe init, expand/collapse, reply mode
//   3. DOM restructuring: hi-res avatars, localized delete buttons,
//      reply folding (YouTube-style), tree branch visuals
//   4. Bootstrap: MutationObserver wiring
// All scoped here. Nothing leaks to global scope.
// ====================================================================
(function() {
    'use strict';

    // ── 1. i18n strings ──────────────────────────────────────────────
    const TEXT_REPLY    = '<span class="lang-zh"><span class="variant-simp">回复</span><span class="variant-trad">回覆</span></span><span class="lang-en">Reply</span>';
    const TEXT_CANCEL   = '<span class="lang-zh"><span class="variant-simp">取消回复</span><span class="variant-trad">取消回覆</span></span><span class="lang-en">Cancel</span>';
    const TEXT_WRITE    = '<span class="lang-zh"><span class="variant-simp">写留言</span><span class="variant-trad">寫留言</span></span><span class="lang-en">Write a comment</span>';
    const TEXT_COLLAPSE = '<span class="lang-zh"><span class="variant-simp">收起留言框</span><span class="variant-trad">收起留言框</span></span><span class="lang-en">Collapse comment box</span>';
    const TEXT_DELETE   = '<span class="lang-zh"><span class="variant-simp">删除</span><span class="variant-trad">刪除</span></span><span class="lang-en">Delete</span>';

    // ── 2. Form lifecycle ────────────────────────────────────────────
    // Encapsulates the Blogger comment iframe in our own .form-inner
    // wrapper so we can apply RTL trick + color filters. Single iframe
    // is reused for both the top-level form and inline reply forms,
    // moved around via DOM relocation.

    function initFormLifecycle() {
        const commentToggleBtn = document.getElementById("comment-toggle");
        const commentsWrapper = document.querySelector(".comments-wrapper");
        const customFormContainer = document.getElementById("custom-comment-form-container");

        if (!commentsWrapper || !customFormContainer) return;

        // One-shot iframe initializer. Returns true once iframe is wrapped.
        function initializeCommentIframe() {
            const editorIframe = document.getElementById("comment-editor");
            if (!editorIframe) return false;
            const formInner = document.createElement('div');
            formInner.className = 'form-inner';
            formInner.appendChild(editorIframe);
            customFormContainer.appendChild(formInner);
            commentsWrapper.classList.add("show-main-form");
            customFormContainer.classList.add("is-expanded");
            if (commentToggleBtn) commentToggleBtn.innerHTML = TEXT_COLLAPSE;
            return true;
        }

        // Try immediate init; otherwise watch DOM for iframe arrival.
        // 8s safety timeout disconnects observer if iframe never shows
        // (e.g. comments disabled on this post).
        if (!initializeCommentIframe()) {
            const iframeObserver = new MutationObserver(() => {
                if (initializeCommentIframe()) iframeObserver.disconnect();
            });
            iframeObserver.observe(commentsWrapper, { childList: true, subtree: true });
            setTimeout(() => iframeObserver.disconnect(), 8000);
        }

        // Toggle button: write ↔ collapse
        if (commentToggleBtn) {
            commentToggleBtn.addEventListener("click", e => {
                e.preventDefault();
                const editorIframe = document.getElementById("comment-editor");
                const isExpanded = commentsWrapper.classList.contains("show-main-form");

                // Reset any active inline reply buttons
                document.querySelectorAll(".comment-reply.cancel-active").forEach(btn => {
                    btn.classList.remove("cancel-active");
                    btn.innerHTML = TEXT_REPLY;
                });

                if (isExpanded) {
                    commentsWrapper.classList.remove("show-main-form");
                    commentToggleBtn.innerHTML = TEXT_WRITE;
                    customFormContainer.classList.remove("is-expanded");
                } else {
                    // Returning from a reply context to the main form.
                    // The container may currently sit under some
                    // comment's .item-control AND still be expanded.
                    // Teleporting it back to the top would skip the
                    // collapse animation entirely. So: collapse first,
                    // relocate when the collapse settles, then expand
                    // in the new position to play the open animation.
                    const mainComments = document.getElementById("comments");
                    const formInner = customFormContainer.querySelector('.form-inner');
                    const srcLink = document.getElementById("comment-editor-src");
                    const wasExpanded = customFormContainer.classList.contains("is-expanded");
                    const alreadyAtTop = customFormContainer.parentNode === commentsWrapper &&
                                         customFormContainer.nextSibling === mainComments;

                    const relocateAndExpand = () => {
                        if (mainComments && !alreadyAtTop) {
                            commentsWrapper.insertBefore(customFormContainer, mainComments);
                        }
                        if (editorIframe && formInner && !formInner.contains(editorIframe)) {
                            formInner.appendChild(editorIframe);
                        }
                        if (srcLink && editorIframe && editorIframe.src !== srcLink.href) {
                            editorIframe.src = srcLink.href;
                        }
                        commentsWrapper.classList.add("show-main-form");
                        commentToggleBtn.innerHTML = TEXT_COLLAPSE;
                        void customFormContainer.offsetWidth;  // force reflow
                        customFormContainer.classList.add("is-expanded");
                    };

                    if (wasExpanded && !alreadyAtTop) {
                        // Phase 1: collapse where it currently sits.
                        customFormContainer.classList.remove("is-expanded");
                        // Phase 2: wait for collapse to finish, then
                        // relocate + re-expand. 320ms matches the
                        // 0.3s grid-template-rows transition + tiny
                        // safety buffer. transitionend would be more
                        // precise but fires for every transitioned
                        // property (grid-rows AND opacity AND margin),
                        // adding event-cleanup complexity for no gain.
                        setTimeout(relocateAndExpand, 320);
                    } else {
                        relocateAndExpand();
                    }
                }
            });
        }

        // Inline reply button delegation. Clicking a reply button on
        // an existing comment relocates the shared iframe under that
        // comment, switching the form into "reply mode". Clicking
        // again (now showing "Cancel") returns the form to the top.
        document.body.addEventListener("click", e => {
            const replyBtn = e.target.closest(".comment-reply");
            if (!replyBtn) return;

            const isCancel = replyBtn.classList.contains("cancel-active");
            const iframe = document.getElementById("comment-editor");
            const formInner = customFormContainer.querySelector('.form-inner');

            // Snap-hide iframe during relocation to avoid flicker
            if (iframe) { iframe.style.transition = 'none'; iframe.style.opacity = '0'; }
            if (customFormContainer) {
                customFormContainer.style.transition = 'none';
                customFormContainer.classList.remove("is-expanded");
            }

            setTimeout(() => {
                // Clear any other active reply buttons
                document.querySelectorAll(".comment-reply.cancel-active").forEach(btn => {
                    if (btn !== replyBtn) {
                        btn.classList.remove("cancel-active");
                        btn.innerHTML = TEXT_REPLY;
                    }
                });

                if (isCancel) {
                    // Cancel reply → return form to top
                    replyBtn.classList.remove("cancel-active");
                    replyBtn.innerHTML = TEXT_REPLY;
                    const mainComments = document.getElementById("comments");
                    if (mainComments && formInner && iframe) {
                        formInner.appendChild(iframe);
                        commentsWrapper.insertBefore(customFormContainer, mainComments);
                        const srcLink = document.getElementById("comment-editor-src");
                        if (srcLink) iframe.src = srcLink.href;
                    }
                    commentsWrapper.classList.add("show-main-form");
                    if (commentToggleBtn) commentToggleBtn.innerHTML = TEXT_COLLAPSE;
                } else {
                    // Start reply → move form directly under this
                    // comment's action row (.item-control). Using
                    // insertAdjacentElement('afterend', ...) keeps
                    // the form as a sibling of the actions, NOT a
                    // descendant of .comment — important because
                    // .comment may contain nested replies, and
                    // appending to .comment would push the form
                    // below those replies.
                    replyBtn.classList.add("cancel-active");
                    replyBtn.innerHTML = TEXT_CANCEL;
                    commentsWrapper.classList.remove("show-main-form");
                    if (commentToggleBtn) commentToggleBtn.innerHTML = TEXT_WRITE;

                    const itemControl = replyBtn.closest(".item-control");
                    if (itemControl && formInner && iframe) {
                        itemControl.insertAdjacentElement('afterend', customFormContainer);
                        formInner.appendChild(iframe);
                    }
                }

                // Two-stage restoration (matches the original behavior):
                // First un-hide the container so its expand animation
                // can play; only fade the iframe back in once the
                // container has settled, otherwise the iframe blinks
                // visible inside a still-collapsing container.
                if (customFormContainer) {
                    void customFormContainer.offsetWidth;  // force reflow
                    customFormContainer.style.transition = '';
                    customFormContainer.classList.add("is-expanded");
                }
                if (iframe) {
                    setTimeout(() => {
                        iframe.style.transition = 'opacity 0.4s ease';
                        iframe.style.opacity = '1';
                    }, 50);
                }
            }, 20);
        });
    }

    // ── 3. Comment restructuring (DOM observer) ──────────────────────
    // Blogger's threadedComments injects comment markup asynchronously
    // and unpredictably. We watch the comment container for mutations
    // and run idempotent restructuring passes whenever it changes.

    let restructureTimer;

    function restructureComments() {
        // Avatars → 2x retina. Blogger ships at s35; replies need
        // 48px (24px slot), top-level need 80px (40px slot).
        document.querySelectorAll(".avatar-image-container img:not([data-hires])").forEach(img => {
            const src = img.getAttribute("src");
            if (!src) return;
            const isReply = !!img.closest(".comment-replies");
            const target = isReply ? "s48-c" : "s80-c";
            const updated = src
                .replace(/\/s\d+(-c)?\//, "/" + target + "/")
                .replace(/=s\d+(-c)?(?=$|[&?])/, "=" + target);
            if (updated !== src) img.setAttribute("src", updated);
            img.dataset.hires = "true";
        });

        // Localize native English "Delete" buttons
        document.querySelectorAll(".item-control a:not([data-cleaned-del])").forEach(btn => {
            const lowerText = btn.innerText.trim().toLowerCase();
            if (lowerText === "delete" || lowerText === "删除") {
                btn.innerHTML = TEXT_DELETE;
                btn.dataset.cleanedDel = "true";
            }
        });

        // Clean up duplicated reply buttons, normalize single reply per comment
        document.querySelectorAll(".comment:not([data-cleaned])").forEach(comment => {
            const controls = comment.querySelector(".item-control");
            const replyBtns = comment.querySelectorAll(".comment-reply");
            if (controls && replyBtns.length) {
                controls.appendChild(replyBtns[0]);
                replyBtns[0].style.display = "inline-flex";
                replyBtns[0].innerHTML = replyBtns[0].classList.contains("cancel-active") ? TEXT_CANCEL : TEXT_REPLY;
                for (let i = 1; i < replyBtns.length; i++) replyBtns[i].remove();
                comment.dataset.cleaned = "true";
            }
        });

        // YouTube-style reply folding. Wrap reply list in a grid that
        // animates open/closed via grid-template-rows transition.
        document.querySelectorAll(".comment-replies:not([data-folded])").forEach(thread => {
            const ol = thread.querySelector("ol");
            const nestedComments = thread.querySelectorAll(".comment");
            if (!ol || nestedComments.length === 0) return;

            const parentComment = thread.closest('.comment');

            // Add vertical trunk line connecting parent → replies
            if (parentComment && !parentComment.querySelector(':scope > .thread-trunk')) {
                const trunk = document.createElement('div');
                trunk.className = 'thread-trunk';
                parentComment.insertBefore(trunk, parentComment.firstChild);
            }

            // Wrap the OL in a 2-level container so we can animate
            // grid-template-rows: 0fr ↔ 1fr smoothly
            const wrapper = document.createElement("div");
            wrapper.className = "replies-grid-wrapper";
            const inner = document.createElement("div");
            inner.className = "replies-grid-inner";
            ol.parentNode.insertBefore(wrapper, ol);
            wrapper.appendChild(inner);
            inner.appendChild(ol);

            // Build the "N replies" toggle button
            const toggleBtn = document.createElement("button");
            const hiddenCount = nestedComments.length;
            toggleBtn.className = "reply-toggle-btn";
            toggleBtn.dataset.count = hiddenCount;

            const buildLabel = isExpanded => {
                const arrowSvg = '<svg viewBox="0 0 24 24"><path d="M7 10l5 5 5-5z"/></svg>';
                if (isExpanded) {
                    return arrowSvg +
                        '<span class="lang-zh"><span class="variant-simp">收起回复</span><span class="variant-trad">收起回覆</span></span>' +
                        '<span class="lang-en">Collapse replies</span>';
                }
                const enText = hiddenCount === 1 ? 'reply' : 'replies';
                return arrowSvg +
                    '<span class="lang-zh"><span class="variant-simp">' + hiddenCount + ' 条回复</span><span class="variant-trad">' + hiddenCount + ' 則回覆</span></span>' +
                    '<span class="lang-en">' + hiddenCount + ' ' + enText + '</span>';
            };

            toggleBtn.innerHTML = buildLabel(false);
            toggleBtn.onclick = e => {
                e.preventDefault();
                const isExpanded = toggleBtn.classList.contains("expanded");
                wrapper.classList.toggle("is-expanded", !isExpanded);
                toggleBtn.classList.toggle("expanded");
                toggleBtn.innerHTML = buildLabel(!isExpanded);
            };

            // Insert toggle button right after the wrapper
            if (wrapper.nextSibling) {
                wrapper.parentNode.insertBefore(toggleBtn, wrapper.nextSibling);
            } else {
                wrapper.parentNode.appendChild(toggleBtn);
            }

            thread.dataset.folded = "true";
        });

        // Add tree-branch visual element to each reply comment
        document.querySelectorAll(".comment-replies .comment:not([data-branched])").forEach(childComment => {
            const branch = document.createElement('div');
            branch.className = 'yt-branch';
            childComment.insertBefore(branch, childComment.firstChild);
            childComment.dataset.branched = "true";
        });

        // Strip Blogger's native "Load more..." links
        const wrapper = document.querySelector(".comments-wrapper");
        if (wrapper) {
            wrapper.querySelectorAll("a, span").forEach(el => {
                const lowerText = el.innerText.trim().toLowerCase();
                if (lowerText === "load more..." || lowerText.includes("load more")) el.remove();
            });
        }
    }

    // ── 4. Bootstrap ─────────────────────────────────────────────────
    // Debounce coalesces Blogger's burst of micro-mutations (it fires
    // dozens of childList events when injecting or re-rendering a
    // comment thread). 16ms = one frame — short enough to never be
    // perceived as a flash, long enough to batch a single user
    // action's worth of mutations into one restructure pass.
    const commentObserver = new MutationObserver(() => {
        clearTimeout(restructureTimer);
        restructureTimer = setTimeout(restructureComments, 16);
    });

    function startObserving() {
        const container = document.getElementById("comments") || document.querySelector(".comments-wrapper");
        if (container) commentObserver.observe(container, { childList: true, subtree: true });
    }

    // Form lifecycle is bound on "load" (waits for Blogger script).
    // Observer starts on "DOMContentLoaded" to catch the first batch
    // of comments even if they're already in the initial HTML.
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', startObserving);
    } else {
        startObserving();
    }
    window.addEventListener("load", initFormLifecycle);
})();
//
